// ── Configuration ─────────────────────────────────────────────
const IMAGE_NAME = env.get("NODE_RED_CONTAINER_NAME");
const TAG_DIR = env.get("NODE_RED_CONTAINER_DIRECTORY");
const TAG_FILE = `${TAG_DIR}/image:tag`;

if (!IMAGE_NAME || !TAG_DIR) {
    node.error("Missing required environment variables: NODE_RED_CONTAINER_NAME and/or NODE_RED_CONTAINER_DIRECTORY");
    return null;
}
// ──────────────────────────────────────────────────────────────

const now = new Date();
const curY = now.getFullYear();
const curM = now.getMonth() + 1;  // 1-12

let newTag;

if (!fs.existsSync(TAG_FILE)) {
    // File does not exist: create with YYYY.MM.1
    newTag = `${curY}.${curM}.1`;

} else {
    const content = fs.readFileSync(TAG_FILE, 'utf8').trim();
    // Expected format: imagename:YYYY.MM.patch
    const match = content.match(/:(\d+)\.(\d+)\.(\d+)$/);

    if (!match) {
        // Unreadable format: reset
        newTag = `${curY}.${curM}.1`;

    } else {
        let [, fileY, fileM, fileP] = match.map(Number);

        if (fileY === curY && fileM === curM) {
            // Same year and month: bump patch
            newTag = `${curY}.${curM}.${fileP + 1}`;

        } else {
            // Different month or year: compute next month
            let nextY = fileY;
            let nextM = fileM + 1;
            if (nextM > 12) {
                nextY += 1;
                nextM = 1;
            }
            newTag = `${nextY}.${nextM}.1`;
        }
    }
}

const fileContent = `${IMAGE_NAME}:${newTag}`;
fs.writeFileSync(TAG_FILE, fileContent, 'utf8');

msg.payload = fileContent;
node.status({ fill: "green", shape: "dot", text: fileContent });
return msg;

const end = new Date(Date.now() - 60 * 60 * 1000);
// zero out minutes, seconds, milliseconds
end.setMinutes(59, 59, 999);
const rfc3339_end = end.toISOString();  

const start = new Date(Date.now() - 60 * 60 * 1000);
// zero out minutes, seconds, milliseconds
start.setMinutes(0, 0, 0);
const rfc3339_start = start.toISOString();  

const now = new Date(); 
const uuid = crypto.randomUUID();

const filename = msg.filename;

const length = msg.size;

msg.payload = {
    "specversion": "1.0",
    "type": "int.wmo.wis.wme.event.log",
    "source": flow.get("sensorid"),
    "subject": flow.get("sensorid"),
    "id": uuid,
    "time": now,
    "datacontenttype": "application/json",
    "dataschema": "https://schemas.wmo.int/wme/1.0.0/schemas/wis2-event-message-encoding-bundled.json",
    "data": {
        "conformsTo": [
            "http://wis.wmo.int/spec/wme/1/conf/monitoring-event-message-encoding-core"
        ],
        "time": {
            "interval": [
                rfc3339_start, rfc3339_end
            ]
        },
        "severity": "INFO",
        "links": [{
            "rel": "canonical",
            "type": "application/gzip",
            "href": flow.get("url") + "/" + filename,
            "length": length
        }]
    }
}

msg.topic="monitor/a/wis2/" + flow.get("sensorid")

return msg;

const filename = msg.filepath;

const exists = fs.existsSync(filename);

msg.exists = exists

if (exists) {
    const stats = fs.statSync(filename);
    msg.size = stats.size; // size in bytes
}

return msg;

const keys = flow.get("gc") || [];
const testKeys = flow.get("gc_test") || [];
const mixed = msg.payload;
const centreid = msg.centreid;

let complete = true;
msg.sampled = false;

// Convert mixed array to key-value map
const resultMap = {};
for (let i = 0; i < mixed.length; i += 2) {
    resultMap[mixed[i]] = mixed[i + 1];
}

// Add missing keys with value 9999999999999
// Test GCs are still recorded (for Download / metrics) but don't block completeness.
keys.forEach(key => {
    if (!(key in resultMap)) {
        resultMap[key] = "9999999999999";
        if (!testKeys.includes(key)) {
            complete = false;
        }
    }
});

// Add centre-id
resultMap["centre-id"] = centreid;

// Parse wnm
const parsedWnm = JSON.parse(resultMap["wnm"]);
resultMap["wnm"] = parsedWnm;

Object.freeze(parsedWnm);
Object.freeze(resultMap);

msg.payload = resultMap;

// Always maintain the rate limit window
const now = Date.now();
const current1min = Math.floor(now / 60000);
let periodCount = flow.get("samplePeriodCount") || 0;
let periodSlot = flow.get("samplePeriodSlot") || 0;

if (current1min !== periodSlot) {
    periodCount = 0;
    flow.set("samplePeriodSlot", current1min);
    flow.set("samplePeriodCount", periodCount);
}

if (complete) {
    const integrity = parsedWnm?.properties?.integrity;
    const canonicalLink = parsedWnm?.links?.find(
        link => link.rel === "canonical" && link.length != null
    );

    if (periodCount < 5 && integrity?.method && integrity?.value && canonicalLink && canonicalLink.length <= 20000) {
        msg.method = integrity.method;
        msg.value = integrity.value;
        msg.originlink = canonicalLink;
        msg.sampled = true;
        flow.set("samplePeriodCount", periodCount + 1);
    }
}

return msg;

const MAX_RETRIES = 3;
const RETRY_DELAY_MS = 1000;

const payload = msg.payload;

const urlEntries = Object.entries(payload)
    .filter(([key]) => key.endsWith(":url"))
    .map(([key, url]) => ({ cacheName: key.replace(/:url$/, ""), url }));

if (!msg.method || !msg.value) {
    return null;
}

async function sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

// Bypass libuv's threadpool for DNS - dns.resolve4 uses c-ares (async I/O)
// instead of the 4-thread pool that dns.lookup() (and fs.*) shares.
function fastLookup(hostname, options, callback) {
    if (typeof options === "function") {
        callback = options;
        options = {};
    }
    dns.resolve4(hostname, (err, addresses) => {
        if (err || !addresses || addresses.length === 0) {
            return dns.lookup(hostname, options, callback);
        }
        callback(null, addresses[0], 4);
    });
}

async function downloadAndHash(url) {
    for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
        try {
            const result = await new Promise((resolve, reject) => {
                let settled = false;
                let req;

                const timer = setTimeout(() => {
                    if (settled) return;
                    settled = true;
                    if (req) req.destroy(new Error("Timed out after 15000ms"));
                    reject(new Error("Timed out after 15000ms"));
                }, 15000);

                const lib = url.startsWith("https") ? https : http;

                req = lib.get(url, {
                    family: 4,
                    lookup: fastLookup,
                    headers: { "User-Agent": "wis2-sensor/1.0" }
                }, (res) => {
                    if (settled) return;

                    if (res.statusCode < 200 || res.statusCode >= 300) {
                        res.resume();
                        settled = true;
                        clearTimeout(timer);
                        return reject(new Error(`HTTP ${res.statusCode}`));
                    }

                    const chunks = [];
                    res.on("data", chunk => chunks.push(chunk));
                    res.on("end", () => {
                        if (settled) return;
                        settled = true;
                        clearTimeout(timer);
                        resolve(Buffer.concat(chunks));
                    });
                    res.on("error", (err) => {
                        if (settled) return;
                        settled = true;
                        clearTimeout(timer);
                        reject(err);
                    });
                });

                req.on("error", (err) => {
                    if (settled) return;
                    settled = true;
                    clearTimeout(timer);
                    reject(err);
                });
            });
            return crypto.createHash(msg.method).update(result).digest("base64");
        } catch (err) {
            if (attempt < MAX_RETRIES) await sleep(RETRY_DELAY_MS);
        }
    }
    return null;
}

(async () => {
    const sensorid = flow.get("sensorid");

    const results = await Promise.allSettled(urlEntries.map(async ({ cacheName, url }) => {
        const hash = await downloadAndHash(url);
        if (hash === null) return { cacheName, url, match: false, downloaded: false };
        return { cacheName, url, match: hash === msg.value, downloaded: true };
    }));

    const sample = {};

    results.forEach((result, i) => {
        if (result.status === "fulfilled" && result.value !== null) {
            const { cacheName, match, downloaded } = result.value;

            sample[cacheName] = downloaded ? 1 : 0;

            node.send([{
                ...msg,
                payload: {
                    op: "inc",
                    labels: {
                        global_cache: cacheName,
                        report_by: sensorid
                    },
                    val: downloaded ? 1 : 0
                }
            }, null]);
        }
    });

    node.send([null, {
        ...msg,
        payload: msg.payload,
        sample
    }]);
})();

return null;

const payload = { ...msg.payload };  // unfreeze
msg.payload = payload;
const sample = msg.sample; 

const globalCache = {};

Object.keys(payload)
    .filter(k => k.endsWith("-global-cache"))
    .forEach(cacheName => {
        const entry = {
            timestamp: payload[cacheName]
        };

        if (payload[`${cacheName}:url`] !== undefined) {
            entry.url = payload[`${cacheName}:url`];
        }
        if (sample !== undefined) {
            entry.downloaded = sample[cacheName] === 1;
        }

        globalCache[cacheName] = entry;

        delete payload[cacheName];
        delete payload[`${cacheName}:url`];
    });

msg.payload["global-cache"] = globalCache;

return msg;

const gcList = flow.get("gc") || [];
const arr = Array.isArray(msg.payload) ? msg.payload : [];

const map = {};
for (let i = 0; i < arr.length; i += 2) {
    map[arr[i]] = arr[i + 1];
}

const dataKey = msg.hset_data[0];
const earlyKey = "early#" + dataKey.slice("data#".length);

const found = gcList.filter(name => Object.prototype.hasOwnProperty.call(map, name));
const remaining = gcList.filter(name => !Object.prototype.hasOwnProperty.call(map, name));

// Output 1: caches still needing a scgc# placeholder. payload must NOT
// carry over the stale HGETALL result into the downstream SET.
const remainingMsg = { ...msg };
remainingMsg.gc = remaining;
delete remainingMsg.payload;

if (found.length === 0) {
    return [remainingMsg, null, null, null];
}

// Output 2: merge the early confirmations into the data# hash.
// topic carries the HSET args; payload must be absent, not duplicated.
const hsetArgs = [dataKey];
found.forEach(name => {
    hsetArgs.push(name, map[name]);
    if (Object.prototype.hasOwnProperty.call(map, name + ":url")) {
        hsetArgs.push(name + ":url", map[name + ":url"]);
    }
});
const mergeMsg = { ...msg, topic: hsetArgs };
delete mergeMsg.payload;

// Output 3: one message per reconciled cache - payload IS the timestamp
// here, on purpose, read directly by the delay/metric nodes downstream.
const perCache = found.map(name => {
    const m = { ...msg };
    m.cache = name;
    m.payload = Number(map[name]);
    delete m.topic;
    return m;
});

// Output 4: clean up the early# hash - topic only, no payload.
const cleanupMsg = { ...msg, topic: earlyKey };
delete cleanupMsg.payload;

return [remainingMsg, mergeMsg, perCache, cleanupMsg];

const gcTest = flow.get("gc_test") || [];
if (gcTest.includes(msg.cache)) {
    // Test caches are never actually reachability-checked - always pass through.
    msg.statusCode = 200;
    return msg;
}

const link = (msg.cache_links || []).find(l => l.rel === 'canonical' || l.rel === 'update');
const url = link ? link.href : null;

if (!url) {
    // No URL → stop flow
    return null;
}

// Bypass libuv's threadpool for DNS - dns.resolve4 uses c-ares (async I/O)
// instead of the 4-thread pool that dns.lookup() (and fs.*) shares.
function fastLookup(hostname, options, callback) {
    if (typeof options === "function") {
        callback = options;
        options = {};
    }
    dns.resolve4(hostname, (err, addresses) => {
        if (err || !addresses || addresses.length === 0) {
            return dns.lookup(hostname, options, callback);
        }
        callback(null, addresses[0], 4);
    });
}

return new Promise((resolve, reject) => {
    const client = url.startsWith("https") ? https : http;
    let settled = false;

    const req = client.request(url, {
        method: "HEAD",
        timeout: 10000,
        family: 4,
        lookup: fastLookup
    }, (res) => {
        if (settled) return;
        const code = res.statusCode;

        if (code !== 200) {
            // ❌ Not 200 → stop flow
            settled = true;
            resolve(null);
            return;
        }

        // ✔ 200 → continue
        settled = true;
        msg.statusCode = code;
        msg.url = url;
        msg.rel = link.rel;   // 'canonical' or 'update'
        resolve(msg);
    });

    req.on("timeout", () => {
        // ⏱ No response within 10s → mark as 404, stop flow
        if (settled) return;
        settled = true;
        req.destroy();
        msg.statusCode = 404;
        resolve(null);
    });

    req.on("error", (err) => {
        // ❌ Error → stop flow
        if (settled) return;
        settled = true;
        resolve(null);
    });

    req.end();
});
